import { QrCode as QrCodePrimitive, useQrCode } from '@ark-ui/react/qr-code';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './QrCode.module.css';

const QrCodeRoot = forwardRef<
  ComponentRef<typeof QrCodePrimitive.Root>,
  ComponentProps<typeof QrCodePrimitive.Root>
>(function QrCodeRoot({ className, ...props }, ref) {
  return (
    <QrCodePrimitive.Root
      ref={ref}
      data-slot="qr-code-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const QrCodeRootProvider = forwardRef<
  ComponentRef<typeof QrCodePrimitive.RootProvider>,
  ComponentProps<typeof QrCodePrimitive.RootProvider>
>(function QrCodeRootProvider({ className, ...props }, ref) {
  return (
    <QrCodePrimitive.RootProvider
      ref={ref}
      data-slot="qr-code-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const QrCodeFrame = forwardRef<
  ComponentRef<typeof QrCodePrimitive.Frame>,
  ComponentProps<typeof QrCodePrimitive.Frame>
>(function QrCodeFrame({ className, ...props }, ref) {
  return (
    <QrCodePrimitive.Frame
      ref={ref}
      data-slot="qr-code-frame"
      className={clsx(styles.frame, normalizeClassName(className))}
      {...props}
    />
  );
});

const QrCodePattern = forwardRef<
  ComponentRef<typeof QrCodePrimitive.Pattern>,
  ComponentProps<typeof QrCodePrimitive.Pattern>
>(function QrCodePattern({ className, ...props }, ref) {
  return (
    <QrCodePrimitive.Pattern
      ref={ref}
      data-slot="qr-code-pattern"
      className={clsx(styles.pattern, normalizeClassName(className))}
      {...props}
    />
  );
});

const QrCodeOverlay = forwardRef<
  ComponentRef<typeof QrCodePrimitive.Overlay>,
  ComponentProps<typeof QrCodePrimitive.Overlay>
>(function QrCodeOverlay({ className, ...props }, ref) {
  return (
    <QrCodePrimitive.Overlay
      ref={ref}
      data-slot="qr-code-overlay"
      className={clsx(styles.overlay, normalizeClassName(className))}
      {...props}
    />
  );
});

const QrCodeDownloadTrigger = forwardRef<
  ComponentRef<typeof QrCodePrimitive.DownloadTrigger>,
  ComponentProps<typeof QrCodePrimitive.DownloadTrigger>
>(function QrCodeDownloadTrigger({ className, ...props }, ref) {
  return (
    <QrCodePrimitive.DownloadTrigger
      ref={ref}
      data-slot="qr-code-download-trigger"
      className={clsx(styles.downloadTrigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const QrCode = Object.assign(QrCodeRoot, {
  Root: QrCodeRoot,
  RootProvider: QrCodeRootProvider,
  Frame: QrCodeFrame,
  Pattern: QrCodePattern,
  Overlay: QrCodeOverlay,
  DownloadTrigger: QrCodeDownloadTrigger,
});

export { QrCode, useQrCode };

@layer ui.components {
  .root {
    position: relative;
    box-sizing: border-box;
    display: inline-flex;
    flex-direction: column;
    align-items: center;
    gap: var(--qr-code-gap, var(--spacing-3));
    width: fit-content;
    max-width: var(--qr-code-max-width, 100%);
    color: var(--qr-code-color, var(--color-foreground));
  }

  .frame {
    box-sizing: border-box;
    display: block;
    width: min(var(--qr-code-size, 8rem), 100%);
    aspect-ratio: 1;
    height: auto;
    color: inherit;
    fill: var(--qr-code-fill, currentColor);
  }

  .pattern {
    fill: inherit;
  }

  .overlay {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--qr-code-overlay-size, 2.5rem);
    height: var(--qr-code-overlay-size, 2.5rem);
    padding: var(--qr-code-overlay-padding, var(--spacing-1));
    border-radius: var(--qr-code-overlay-radius, var(--radius-sm));
    background-color: var(--qr-code-overlay-bg, var(--color-background));
    color: var(--qr-code-overlay-color, var(--color-foreground));
  }

  .overlay :where(img, svg) {
    width: 100%;
    height: 100%;
    object-fit: contain;
  }

  .downloadTrigger {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--qr-code-download-trigger-gap, var(--button-content-gap, var(--spacing-2)));
    min-height: var(--qr-code-download-trigger-height, var(--button-size-md, var(--size-lg)));
    padding-inline: var(--qr-code-download-trigger-padding-x, var(--button-padding-x-md, 1rem));
    border: var(
        --qr-code-download-trigger-border-width,
        var(--button-border-width, var(--border-width-sm))
      )
      solid
      var(
        --qr-code-download-trigger-border-color,
        var(--button-outline-border-color, var(--color-border))
      );
    border-radius: var(--qr-code-download-trigger-radius, var(--button-radius, var(--radius-md)));
    background-color: var(
      --qr-code-download-trigger-bg,
      var(--button-outline-bg, var(--color-background))
    );
    color: var(
      --qr-code-download-trigger-color,
      var(--button-outline-color, var(--color-foreground))
    );
    appearance: none;
    font: inherit;
    font-size: var(--qr-code-download-trigger-font-size, var(--button-font-size, var(--text-sm)));
    font-weight: var(
      --qr-code-download-trigger-font-weight,
      var(--button-font-weight, var(--weight-medium))
    );
    line-height: var(
      --qr-code-download-trigger-line-height,
      var(--button-line-height, var(--line-height-text-sm))
    );
    user-select: none;
    white-space: nowrap;
    cursor: pointer;
    transition:
      border-color var(--qr-code-transition, var(--button-transition, var(--transition-default))),
      background-color
        var(--qr-code-transition, var(--button-transition, var(--transition-default))),
      color var(--qr-code-transition, var(--button-transition, var(--transition-default))),
      opacity var(--qr-code-transition, var(--button-transition, var(--transition-default))),
      box-shadow var(--qr-code-transition, var(--button-transition, var(--transition-default)));
  }

  .downloadTrigger :where(svg) {
    width: var(--qr-code-download-trigger-icon-size, var(--button-icon-size, 1rem));
    height: var(--qr-code-download-trigger-icon-size, var(--button-icon-size, 1rem));
    flex-shrink: 0;
  }

  @media (hover: hover) {
    .downloadTrigger:hover:not(:disabled, [data-disabled]) {
      background-color: var(
        --qr-code-download-trigger-bg-hover,
        var(--button-outline-bg-hover, var(--color-accent))
      );
    }
  }

  .downloadTrigger:focus-visible {
    outline: var(
        --qr-code-download-trigger-focus-ring-width,
        var(--button-focus-ring-width, var(--border-width-md))
      )
      solid
      var(
        --qr-code-download-trigger-focus-ring-color,
        var(--button-focus-ring-color, var(--color-ring))
      );
    outline-offset: calc(
      var(
          --qr-code-download-trigger-focus-ring-offset,
          var(
            --qr-code-download-trigger-border-width,
            var(--button-border-width, var(--border-width-sm))
          )
        ) *
        -1
    );
  }

  .downloadTrigger:disabled,
  .downloadTrigger[data-disabled] {
    pointer-events: none;
    opacity: var(
      --qr-code-disabled-opacity,
      var(--button-disabled-opacity, var(--opacity-disabled))
    );
  }
}
